package com.google.gson;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.math.BigDecimal;
import java.math.BigInteger;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  JsonElement jsonElementMock;
  JsonNull jsonNullMock;

  @BeforeEach
  void setUp() {
    jsonElementMock = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    jsonNullMock = mock(JsonNull.class);
  }

  @Test
  void getAsJsonNull_whenIsJsonNullTrue_returnsThisAsJsonNull() {
    when(jsonElementMock.isJsonNull()).thenReturn(true);
    // Cast this (mock) to JsonNull to simulate the method behavior
    // We need to mock that jsonElementMock is a JsonNull instance
    // So we create a spy of JsonNull and call getAsJsonNull on it
    JsonNull jsonNullSpy = spy(JsonNull.class);
    when(jsonNullSpy.isJsonNull()).thenReturn(true);
    JsonNull result = jsonNullSpy.getAsJsonNull();
    assertSame(jsonNullSpy, result);
  }

  @Test
  void getAsJsonNull_whenIsJsonNullFalse_throwsIllegalStateException() {
    when(jsonElementMock.isJsonNull()).thenReturn(false);
    IllegalStateException exception = assertThrows(IllegalStateException.class, () -> {
      // Avoid toString() call on mock by overriding toString()
      when(jsonElementMock.toString()).thenReturn("JsonElementMock");
      jsonElementMock.getAsJsonNull();
    });
    assertTrue(exception.getMessage().startsWith("Not a JSON Null: "));
  }
}
